import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("returns 5 G for an empty item list (processing fee only)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it.todo("computes base premium for a single sword (100 G + 5 G fee = 105 G)");
    it.todo("computes base premium for a single amulet (60 G + 5 G fee = 65 G)");
    it.todo("computes base premium for a single staff (80 G + 5 G fee = 85 G)");
    it.todo("computes base premium for a single potion (40 G + 5 G fee = 45 G)");
    it.todo("computes base premium for a single component (25 G + 5 G fee = 30 G)");
    it.todo("computes base premium for multiple items (sword + amulet = 160 G + 5 G fee = 165 G)");
  });

  describe("Quote - component blocks", () => {
    it.todo("applies block discount for exactly 3 alike components (60 G + 5 G fee = 65 G)");
    it.todo("does not apply block for 2 alike components (50 G + 5 G fee = 55 G)");
    it.todo("does not apply block for 4 alike components (100 G + 5 G fee = 105 G)");
    it.todo("does not apply block for 3 components of different types (75 G + 5 G fee = 80 G)");
    it.todo("applies two separate blocks for 3 runes + 3 moonstones (120 G + 5 G fee = 125 G)");
  });

  describe("Quote - item-specific modifiers", () => {
    it.todo("adds 50% cursed surcharge to a cursed item's base premium");
    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
    it.todo("applies both cursed and high-enchantment surcharges to the same item");
    it.todo("does not apply high-enchantment surcharge for enchantment level 4");
    it.todo("applies item-specific surcharges only to the affected item in a multi-item policy");
  });

  describe("Quote - policy-wide modifiers", () => {
    it.todo("applies 10% first-insurance surcharge on policy base premium");
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 15% follow-up contract discount on second quote");
    it.todo("applies loyalty, first-insurance, and follow-up modifiers together");
  });

  describe("Quote - rounding", () => {
    it.todo("rounds premium up (in MHPCO's favor) to whole G");
  });

  describe("Claim - basic payout", () => {
    it.todo("reimburses damage minus 100 G deductible for a regular item");
    it.todo("applies deductible per damaged item in a single event");
    it.todo("reimburses component damage minus deductible");
  });

  describe("Claim - special reimbursement rules", () => {
    it.todo("reimburses at 50% for items with enchantment level >= 8");
    it.todo("fully reimburses dragon-material items");
    it.todo("applies 50% rule when item is both dragon-material and enchantment >= 8");
    it.todo("fully reimburses dragon-material item with enchantment < 8");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at twice the insurance sum");
    it.todo("tracks remaining cap across multiple claims on the same policy");
    it.todo("returns remaining cap of 0 when cap is exhausted");
  });

  describe("Claim - rounding", () => {
    it.todo("rounds payout down (in MHPCO's favor) to whole G");
  });

  describe("Error handling", () => {
    it.todo("rejects unknown item type in quote");
    it.todo("rejects claim for item not in the policy");
    it.todo("rejects negative damage amount");
    it.todo("rejects more damages of a type than insured items of that type");
  });

  describe("Integration - newcomer with cursed sword", () => {
    it.todo("computes 165 G for a newcomer with a cursed sword");
  });

  describe("Integration - long-standing customer second contract", () => {
    it.todo("computes 160 G for a long-standing customer's second contract with cursed high-enchantment sword");
  });
});

