      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it("computes base premium for a single sword (100 G + 5 G fee = 105 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it("computes base premium for a single amulet (60 G + 5 G fee = 65 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 65 });
    });
    it("computes base premium for a single staff (80 G + 5 G fee = 85 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 85 });
    });
    it("computes base premium for a single potion (40 G + 5 G fee = 45 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 45 });
    });
    it("computes base premium for a single component (25 G + 5 G fee = 30 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "rune" }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 30 });
    });
    it("computes base premium for multiple items (sword + amulet = 160 G + 5 G fee = 165 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 165 });
    });
  });

  describe("Quote - component blocks", () => {
    it.todo("applies block discount for exactly 3 alike components (60 G + 5 G fee = 65 G)");
    it.todo("does not apply block for 2 alike components (50 G + 5 G fee = 55 G)");
    it.todo("does not apply block for 4 alike components (100 G + 5 G fee = 105 G)");
    it.todo("does not apply block for 3 components of different types (75 G + 5 G fee = 80 G)");
    it.todo("applies two separate blocks for 3 runes + 3 moonstones (120 G + 5 G fee = 125 G)");
  });

  describe("Quote - item-specific modifiers", () => {
    it.todo("adds 50% cursed surcharge to a cursed item's base premium");
    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
    it.todo("applies both cursed and high-enchantment surcharges to the same item");
