import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("returns 5 G for an empty item list (processing fee only)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it("computes base premium for a single sword (100 G + 5 G fee = 105 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it("computes base premium for a single amulet (60 G + 5 G fee = 65 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 65 });
    });
    it("computes base premium for a single staff (80 G + 5 G fee = 85 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 85 });
    });
    it("computes base premium for a single potion (40 G + 5 G fee = 45 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 45 });
    });
    it("computes base premium for a single component (25 G + 5 G fee = 30 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "rune" }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 30 });
    });
    it("computes base premium for multiple items (sword + amulet = 160 G + 5 G fee = 165 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 165 });
    });
  });

  describe("Quote - component blocks", () => {
    it("applies block discount for exactly 3 alike components (60 G + 5 G fee = 65 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 65 });
    });
    it("does not apply block for 2 alike components (50 G + 5 G fee = 55 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "rune" }, { type: "rune" }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 55 });
    });
    it("does not apply block for 4 alike components (100 G + 5 G fee = 105 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it("does not apply block for 3 components of different types (75 G + 5 G fee = 80 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 80 });
    });
    it("applies two separate blocks for 3 runes + 3 moonstones (120 G + 5 G fee = 125 G)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 125 });
    });
  });

  describe("Quote - item-specific modifiers", () => {
    it("adds 50% cursed surcharge to a cursed item's base premium", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 155 });
    });
    it("adds 30% high-enchantment surcharge for enchantment level >= 5", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 135 });
    });
    it("applies both cursed and high-enchantment surcharges to the same item", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 185 });
    });
    it("does not apply high-enchantment surcharge for enchantment level 4", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 105 });
    });
    it("applies item-specific surcharges only to the affected item in a multi-item policy", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: true },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 215 });
    });
  });

  describe("Quote - policy-wide modifiers", () => {
    it("applies 10% first-insurance surcharge on policy base premium", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote" as const,
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 15% follow-up contract discount on second quote");
    it.todo("applies loyalty, first-insurance, and follow-up modifiers together");
  });

  describe("Quote - rounding", () => {
    it.todo("rounds premium up (in MHPCO's favor) to whole G");
  });

  describe("Claim - basic payout", () => {
    it.todo("reimburses damage minus 100 G deductible for a regular item");
    it.todo("applies deductible per damaged item in a single event");
    it.todo("reimburses component damage minus deductible");
  });

  describe("Claim - special reimbursement rules", () => {
    it.todo("reimburses at 50% for items with enchantment level >= 8");
    it.todo("fully reimburses dragon-material items");
    it.todo("applies 50% rule when item is both dragon-material and enchantment >= 8");
    it.todo("fully reimburses dragon-material item with enchantment < 8");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at twice the insurance sum");
    it.todo("tracks remaining cap across multiple claims on the same policy");
    it.todo("returns remaining cap of 0 when cap is exhausted");
  });

  describe("Claim - rounding", () => {
    it.todo("rounds payout down (in MHPCO's favor) to whole G");
  });

  describe("Error handling", () => {
    it.todo("rejects unknown item type in quote");
    it.todo("rejects claim for item not in the policy");
    it.todo("rejects negative damage amount");
    it.todo("rejects more damages of a type than insured items of that type");
  });

  describe("Integration - newcomer with cursed sword", () => {
    it.todo("computes 165 G for a newcomer with a cursed sword");
  });

  describe("Integration - long-standing customer second contract", () => {
    it.todo("computes 160 G for a long-standing customer's second contract with cursed high-enchantment sword");
  });
});

