function computeBasePremium(items: any[]): number {
  return computeMainItemPremium(items) + computeComponentPremium(items);
}

export function processScenario(scenario: any): any {
  const step = scenario.steps[0];
  const basePremium = computeBasePremium(step.items);
  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
}

input.new_string:
function computeItemAdjustedPremium(items: any[]): number {
  return computeMainItemPremium(items) + computeComponentPremium(items);
}

function computePolicyBasePremium(items: any[]): number {
  let total = 0;
  for (const item of items) {
    if (!isComponent(item.type)) {
      total += MAIN_ITEM_PREMIUMS[item.type];
    }
  }
  total += computeComponentPremium(items);
  return total;
}

const FIRST_INSURANCE_RATE = 0.1;

