  describe("Integration - newcomer with cursed sword", () => {
    it.todo("computes 165 G for a newcomer with a cursed sword");
  });

  describe("Integration - long-standing customer second contract", () => {
    it.todo("computes 160 G for a long-standing customer's second contract with cursed high-enchantment sword");
