const PROCESSING_FEE = 5;
const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const MAIN_ITEM_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

function isComponent(type: string): boolean {
  return !(type in MAIN_ITEM_PREMIUMS);
}

function computeComponentPremium(items: any[]): number {
  const componentCounts: Record<string, number> = {};

  for (const item of items) {
    if (isComponent(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    }
  }

  let premium = 0;
  for (const count of Object.values(componentCounts)) {
    premium += count === COMPONENT_BLOCK_SIZE
      ? COMPONENT_BLOCK_PREMIUM
      : count * COMPONENT_PREMIUM;
  }
  return premium;
}

function computeMainItemPremiums(items: any[]): { base: number; total: number } {
  let base = 0;
  let total = 0;
  for (const item of items) {
    if (!isComponent(item.type)) {
      const basePremium = MAIN_ITEM_PREMIUMS[item.type];
      base += basePremium;
      let itemPremium = basePremium;
      if (item.cursed) {
        itemPremium += basePremium * CURSED_SURCHARGE_RATE;
      }
      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
        itemPremium += basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
      }
      total += itemPremium;
    }
  }
  return { base, total };
}

const FIRST_INSURANCE_RATE = 0.1;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;

export function processScenario(scenario: any): any {
  const results: any[] = [];
  let quoteCount = 0;

  for (const step of scenario.steps) {
    if (step.op === "quote") {
      quoteCount++;
      const componentPremium = computeComponentPremium(step.items);
      const mainItems = computeMainItemPremiums(step.items);
      const totalItemPremium = mainItems.total + componentPremium;
      const policyBase = mainItems.base + componentPremium;
      let policyModifiers = policyBase * FIRST_INSURANCE_RATE;
      if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
        policyModifiers -= policyBase * LOYALTY_DISCOUNT_RATE;
      }
      if (quoteCount > 1) {
        policyModifiers -= policyBase * FOLLOW_UP_DISCOUNT_RATE;
      }
      const premium = Math.ceil(totalItemPremium + policyModifiers + PROCESSING_FEE);
      results.push({ premium });
    }
  }

  return { results };
}

